%%%%%%%%%% Function fTrexFwhmInfV01.m %%%%%%%%%%% Function Figure fwhm Information, ver.1% Kei Nakamura% Created on Saturday, June 9th 2007.% Modified on %% function inf = fTrexFwhmInfV01(sig);% returns a information string for figure%function inf = fTrexfwhmInfV01(anl);  %function headerinf{1} = strcat('peak energy [MeV]:',num2str(ceil(anl.peakEnrgMev)));inf{2} = strcat('resolution [%,fwhm]:',num2str(0.1*ceil(10*anl.rsltnPcnt)));inf{3} = strcat('energy spread [%,fwhm]:',num2str(0.1*ceil(10*anl.engSprdPcnt)));inf{4} = strcat('divergence [mrad,fwhm]:',num2str(0.1*ceil(10*anl.beamDivMrad)));inf{5} = strcat('beam peak angle [mrad]:',num2str(ceil(anl.anglMrad)));
